const title = $('Airtable - Get Content').item.json.Title || '';
const metaDescription = $('Airtable - Get Content').item.json['Meta Description'] || '';
const category = $('Airtable - Get Content').item.json.Category || '';
const content = $('Airtable - Get Content').item.json.Content || '';

// Build the prompt
const userPrompt = `Rewrite and optimize the following article according to all the guidelines. Improve the SEO, enhance the tone, ensure proper formatting, and add inline CTAs naturally.

Original Title: ${title}

Original Meta Description: ${metaDescription}

Original Category: ${category}

Original Content:
${content}

Rewrite this completely following all guidelines in system prompt, maintaining the core topic but making it more engaging, SEO-optimized, and aligned with Tugasin's brand voice.`;

// Return it - n8n will handle escaping when you use ={{ }}
return [{
  json: {
    userPrompt: userPrompt
  }
}];

const content = $('Mistral - Rewrite Content').first().json.choices[0].message.content

// If content starts with "content:", remove ONLY that
const jsonString = content.startsWith('content:')
  ? content.replace(/^content:\s*/, '')
  : content;

// Parse JSON as-is
const parsed = JSON.parse(jsonString);

// n8n requires an ARRAY of items
return [
  {
    json: parsed
  }
];

